#!/usr/bin/env python3
import json

questions = [
  {"id":"ms_011","category":"musculoskeletal","question":"관절염의 종류에는 어떤 것이 있나요?","answer":"퇴행성 관절염(골관절염, 가장 흔함), 류마티스 관절염(자가면역), 통풍성 관절염, 건선성 관절염, 반응성 관절염 등이 있습니다. 각각 원인과 치료 방법이 다릅니다."},
  {"id":"ms_012","category":"musculoskeletal","question":"골다공증이란 무엇이며 어떻게 예방하나요?","answer":"뼈의 밀도가 감소해 골절 위험이 높아지는 질환입니다. 칼슘(1,000~1,200mg/일), 비타민 D(800~1,000IU/일) 충분 섭취, 체중 부하 운동, 금연, 절주가 예방에 중요합니다."},
  {"id":"ms_013","category":"musculoskeletal","question":"허리 디스크와 척추관 협착증의 차이는?","answer":"허리 디스크는 디스크가 탈출해 신경을 압박하며 주로 젊은 층에서, 척추관 협착증은 척추관이 좁아져 신경을 압박하며 주로 노인에서 발생합니다. 협착증은 걸을수록 통증이 심해집니다."},
  {"id":"ms_014","category":"musculoskeletal","question":"근육통과 신경통의 차이는?","answer":"근육통은 근육 피로·손상으로 생기는 뭉치는 통증입니다. 신경통은 신경 압박·손상으로 타는 듯한 찌릿한 방사통이 특징입니다. 신경통은 저림·감각 저하가 동반되는 경우가 많습니다."},
  {"id":"ms_015","category":"musculoskeletal","question":"스트레칭을 매일 해야 하는 이유는?","answer":"스트레칭은 근육 유연성 증가, 관절 가동 범위 유지, 근육 부상 예방, 자세 교정, 혈액순환 개선에 도움됩니다. 특히 오래 앉아 일하는 직장인에게 정기적 스트레칭이 허리·목 건강에 중요합니다."},
  {"id":"ms_016","category":"musculoskeletal","question":"운동 후 근육통(DOMS)이란?","answer":"새로운 운동이나 강도 높은 운동 후 24~48시간에 나타나는 지연성 근육통입니다. 근섬유 미세 손상이 원인이며, 반복 운동으로 점차 줄어듭니다. 온찜질, 가벼운 활동, 마사지가 도움됩니다."},
  {"id":"ms_017","category":"musculoskeletal","question":"류마티스 관절염과 퇴행성 관절염의 차이는?","answer":"류마티스는 자가면역(면역세포가 관절 활막 공격), 양측성·소관절 주로, 아침 강직이 1시간 이상 지속됩니다. 퇴행성은 연골 마모(비면역적), 주로 무릎·고관절·손가락 끝 관절에 발생합니다."},
  {"id":"ms_018","category":"musculoskeletal","question":"오십견(유착성 관절낭염)이란?","answer":"어깨 관절 낭이 수축·유착되어 어깨 움직임이 제한되고 통증이 심한 상태입니다. 자연 경과는 2~3년 내 회복이지만, 물리치료, 관절 내 스테로이드 주사, 운동 치료로 빠른 회복을 도울 수 있습니다."},
  {"id":"ms_019","category":"musculoskeletal","question":"발바닥 통증(족저 근막염)의 치료는?","answer":"족저 근막 스트레칭, 마사지(아침에 일어나기 전), 아이싱, 잘 맞는 신발(쿠션과 아치 지지), 깔창, 항염증제가 효과적입니다. 6주 이상 지속 시 충격파 치료나 스테로이드 주사를 고려합니다."},
  {"id":"ms_020","category":"musculoskeletal","question":"골절 후 뼈가 붙는 데 얼마나 걸리나요?","answer":"골절 치유는 부위·나이·전신 건강에 따라 다릅니다. 손목 골절은 6~8주, 대퇴골(허벅지) 골절은 12~16주, 척추 골절은 8~12주가 일반적입니다. 칼슘·비타민 D 섭취와 금연이 치유를 돕습니다."},
  {"id":"ms_021","category":"musculoskeletal","question":"근육을 키우는 효과적인 방법은?","answer":"점진적 과부하(progressive overload)가 핵심입니다. 주 2~3회 근력 운동, 충분한 단백질(체중 kg×1.6~2.2g/일), 운동 후 회복(충분한 수면), 규칙적인 식사가 근육 성장의 기본 원칙입니다."},
  {"id":"ms_022","category":"musculoskeletal","question":"디스크 예방을 위한 올바른 자세는?","answer":"앉을 때 등을 의자에 밀착하고 허리 지지, 모니터 눈 높이 조정, 1시간마다 일어나 5분 스트레칭, 물건을 들 때 무릎 굽혀 다리로 들기, 한쪽으로 가방 메지 않기가 척추 건강을 지킵니다."},
  {"id":"ms_023","category":"musculoskeletal","question":"무릎 십자인대 손상은 어떻게 치료하나요?","answer":"전방 십자인대(ACL) 파열은 경미하면 재활로, 젊고 활동적인 사람은 수술(관절경) 후 6~9개월 재활이 필요합니다. 후방 십자인대(PCL)는 보존적 치료가 먼저입니다."},
  {"id":"ms_024","category":"musculoskeletal","question":"건초염이란 무엇인가요?","answer":"힘줄을 감싸는 건초에 염증이 생기는 상태로 반복적 움직임이 원인입니다. 손목(드케르벵 증후군), 발목 등에 흔합니다. 휴식, 아이싱, 부목, 스테로이드 주사, 체외충격파로 치료합니다."},
  {"id":"ms_025","category":"musculoskeletal","question":"근감소증(sarcopenia)이란 무엇인가요?","answer":"나이 들면서 근육량과 근력이 감소하는 상태입니다. 낙상, 장애, 사망률 증가와 연관됩니다. 규칙적인 근력 운동과 단백질 충분 섭취(0.8~1.2g/kg/일)가 예방과 치료의 핵심입니다."},
  {"id":"ms_026","category":"musculoskeletal","question":"통풍 발작이 일어나면 어떻게 해야 하나요?","answer":"발작 초기에 NSAIDs(나프록센), 콜히친, 스테로이드로 통증을 완화합니다. 안정, 냉찜질, 요산 줄이는 식이(고기·내장·맥주 제한, 수분 충분)를 유지합니다. 반복 발작 시 알로퓨리놀로 요산 조절 치료를 시작합니다."},
  {"id":"ms_027","category":"musculoskeletal","question":"척추 측만증이란 무엇인가요?","answer":"척추가 좌우로 10도 이상 비정상 만곡된 상태입니다. 특발성(원인 불명, 청소년기 가장 흔함), 선천성, 신경근성이 있습니다. 경미하면 관찰, 20~45도는 보조기, 45도 이상은 수술적 교정을 고려합니다."},
  {"id":"ms_028","category":"musculoskeletal","question":"테니스엘보(외측 상과염)는 어떻게 치료하나요?","answer":"가장 흔한 팔꿈치 외측 통증으로 과도한 손목·팔 사용이 원인입니다. 휴식, 아이싱, NSAIDs, 물리 치료(편심성 운동), 보조기, 체외충격파가 효과적입니다. 대부분 6개월~1년 내 자연 회복됩니다."},
  {"id":"ms_029","category":"musculoskeletal","question":"뼈에 좋은 음식과 나쁜 음식은?","answer":"좋은 음식: 우유·치즈·요거트(칼슘), 연어·고등어(비타민 D), 두부·된장(칼슘+이소플라본), 잎채소(칼슘·마그네슘). 나쁜 것: 과도한 염분(칼슘 배설 증가), 카페인(과다), 알코올, 흡연."},
  {"id":"ms_030","category":"musculoskeletal","question":"무릎 연골 손상은 어떻게 치료하나요?","answer":"경미한 손상은 운동 치료, 체중 감량, 히알루론산 또는 PRP 주사가 도움됩니다. 심한 연골 손상이나 퇴행성 관절염 말기에는 인공관절 치환술이 필요합니다. 줄기세포 치료도 연구 중입니다."},
  {"id":"ms_031","category":"musculoskeletal","question":"엉덩이 근육(둔근)이 약하면 어떤 문제가 생기나요?","answer":"둔근 약화는 골반 불균형, 허리 통증, 무릎 외반, 발목 부상으로 이어집니다. 스쿼트, 런지, 힙 쓰러스트, 클램쉘 등 둔근 강화 운동이 하체 관절 건강에 중요합니다."},
  {"id":"ms_032","category":"musculoskeletal","question":"손목터널증후군의 증상과 치료는?","answer":"수근관 내 정중신경 압박으로 손바닥·엄지·검지·중지에 저림, 타는 통증이 나타납니다. 야간 증상이 특징입니다. 손목 보조기(야간), 스테로이드 주사가 효과적이며 심한 경우 수술(신경 감압)합니다."},
  {"id":"ms_033","category":"musculoskeletal","question":"근육 경련(쥐)이 자주 발생하는 이유는?","answer":"전해질 불균형(나트륨, 칼슘, 마그네슘, 칼륨 부족), 탈수, 과도한 운동, 근육 피로, 약물 부작용, 순환 장애가 원인입니다. 수분·전해질 보충, 스트레칭, 마그네슘 보충이 도움됩니다."},
  {"id":"ms_034","category":"musculoskeletal","question":"어깨 회전근개 손상이란 무엇인가요?","answer":"어깨 안정화에 관여하는 4개 근육(극상근, 극하근, 소원근, 견갑하근)의 건 손상입니다. 어깨 들어올리기·회전 통증이 특징입니다. 재활 운동이 1차 치료이며 완전 파열은 수술이 필요합니다."},
  {"id":"ms_035","category":"musculoskeletal","question":"골밀도 검사는 언제 받아야 하나요?","answer":"여성은 65세부터, 폐경 후 위험 요인(골절 가족력, 흡연, 저체중 등)이 있으면 더 일찍 받습니다. 남성은 70세부터 권장됩니다. T-score -2.5 이하가 골다공증 기준입니다."},
  {"id":"ms_036","category":"musculoskeletal","question":"목 통증(경추통)을 예방하는 방법은?","answer":"스마트폰·모니터를 눈 높이로 조정, 1시간마다 목 스트레칭, 배게 높이 적절히 조정(목 자연 만곡 유지), 목 근력 운동, 한 자세 오래 유지 자제가 경추 건강 유지에 중요합니다."},
  {"id":"ms_037","category":"musculoskeletal","question":"요통에서 코어 강화 운동이 중요한 이유는?","answer":"코어 근육(복횡근, 다열근, 골반저근, 횡경막)은 척추를 안정시키는 자연 코르셋입니다. 약화 시 요추에 과부하가 걸립니다. 플랭크, 데드버그, 버드독 등 코어 운동이 허리 통증 예방·재활에 핵심입니다."},
  {"id":"ms_038","category":"musculoskeletal","question":"관절에 좋은 보충제가 있나요?","answer":"글루코사민과 콘드로이틴은 일부 연구에서 경미~중등도 퇴행성 관절염의 통증 완화에 도움될 수 있습니다. 오메가-3는 항염증 효과로 도움됩니다. 단, 표준 치료를 대체하기에는 근거가 제한적입니다."},
  {"id":"ms_039","category":"musculoskeletal","question":"피로 골절이란 무엇인가요?","answer":"반복적인 미세 외력이 누적되어 뼈에 균열이 생기는 것입니다. 달리기 선수, 군인에서 발·정강이에 흔합니다. 통증이 서서히 시작되고 활동 시 악화됩니다. 충분한 휴식과 활동 감소가 치료의 핵심입니다."},
  {"id":"ms_040","category":"musculoskeletal","question":"인공 관절 수술 후 회복은 얼마나 걸리나요?","answer":"인공 무릎 관절 수술 후 통상 6~12주에 일상 복귀, 3개월에 가벼운 활동, 6개월~1년에 충분한 기능 회복이 가능합니다. 물리치료와 재활 운동이 회복 속도를 크게 좌우합니다."},
  {"id":"ms_041","category":"musculoskeletal","question":"어린이 성장통이란 무엇인가요?","answer":"성장통은 주로 밤에 나타나는 무릎 아래나 정강이의 통증으로, 학령기 어린이(3~12세)에서 흔합니다. 정확한 원인은 불분명하지만 낮의 활동 후 근육 피로로 보기도 합니다. 마사지, 온찜질이 증상 완화에 도움됩니다."},
  {"id":"ms_042","category":"musculoskeletal","question":"비수술적 허리 통증 치료 방법은?","answer":"물리치료(스트레칭·근력 운동·도수치료), NSAIDs 등 약물 치료, 온/냉찜질, 마사지, 침술(일부 근거), 신경 차단술이 사용됩니다. 단순 요통의 90%는 6~12주 내 보존적 치료로 회복됩니다."},
  {"id":"ms_043","category":"musculoskeletal","question":"섬유근통이란 무엇인가요?","answer":"섬유근통은 전신의 만성 근골격계 통증, 피로, 수면 장애, 인지 기능 저하가 특징인 복잡한 질환입니다. 명확한 기질적 원인이 없으며, 운동 치료, 인지행동치료, 약물(프레가발린, 둘록세틴)로 관리합니다."},
  {"id":"ms_044","category":"musculoskeletal","question":"관절 치환술(인공관절) 수명은?","answer":"현대 인공 관절의 수명은 15~25년으로 향상되었습니다. 젊고 활동적인 환자에서 더 빨리 마모될 수 있습니다. 이식 재료(세라믹, 금속, 폴리에틸렌)와 환자 체중·활동 수준이 수명에 영향을 줍니다."},
  {"id":"ms_045","category":"musculoskeletal","question":"스포츠 부상 예방을 위한 핵심 원칙은?","answer":"적절한 워밍업(5~10분 유산소+동적 스트레칭), 올바른 기술 습득, 점진적 훈련 강도 증가(10% 규칙), 충분한 회복, 적합한 장비(신발), 탈수 방지, 코어 근력 유지가 스포츠 부상 예방의 핵심입니다."},
  {"id":"ms_046","category":"musculoskeletal","question":"낙상 예방을 위한 노인의 운동 방법은?","answer":"균형 훈련(타이치, 한발 서기), 하지 근력 운동, 보행 훈련이 낙상 위험을 30~40% 줄입니다. 집안 안전 점검(미끄럼 방지 매트, 손잡이 설치), 시력 교정, 다약제 검토도 낙상 예방에 중요합니다."},
  {"id":"ms_047","category":"musculoskeletal","question":"석회화 건염이란 무엇인가요?","answer":"어깨 회전근개 건 내에 칼슘 결정이 쌓여 극심한 통증을 일으킵니다. 초음파 유도 세척술(석회 제거), 체외충격파가 효과적입니다. 대부분 수 주~수 개월 내 자연 흡수되기도 합니다."},
  {"id":"ms_048","category":"musculoskeletal","question":"발목 인대 손상(염좌)의 등급과 치료는?","answer":"1도(인대 미세 손상): RICE(안정·냉찜질·압박·거상), 2도(부분 파열): 보조기+재활, 3도(완전 파열): 수술이 필요한 경우도 있습니다. 고유감각 훈련이 재발 예방에 중요합니다."},
  {"id":"ms_049","category":"musculoskeletal","question":"근육과 힘줄의 차이는?","answer":"근육은 수축·이완으로 뼈를 움직이는 조직입니다. 힘줄(건)은 근육을 뼈에 연결하는 강인한 결합 조직입니다. 힘줄은 혈류가 적어 근육보다 회복이 느리며, 과부하 시 건병증이 발생합니다."},
  {"id":"ms_050","category":"musculoskeletal","question":"스쿼트가 무릎에 안 좋다는 것은 사실인가요?","answer":"올바른 형태의 스쿼트는 무릎에 해롭지 않습니다. 무릎이 발가락보다 너무 앞으로 나가지 않게, 발 너비와 평행하게, 발뒤꿈치는 바닥에 붙이고 하는 스쿼트는 무릎·둔근 강화에 효과적입니다."},
  {"id":"ms_051","category":"musculoskeletal","question":"요통 환자에게 수영이 좋은 이유는?","answer":"수영은 부력으로 척추에 가해지는 하중을 줄이면서 코어·허리 근육을 강화합니다. 수중 운동은 관절 부담 없이 운동할 수 있어 요통 환자, 비만 환자, 관절염 환자에게 적합합니다."},
  {"id":"ms_052","category":"musculoskeletal","question":"발 아치(족궁)가 무너지는 평발은 어떻게 관리하나요?","answer":"발 아치를 지지하는 맞춤 깔창이 통증 완화에 효과적입니다. 발 내재근 강화 운동(타월 집기, 발가락 컬), 체중 감량, 적합한 신발 선택이 중요합니다. 심한 통증이나 기능 저하 시 수술을 고려합니다."},
  {"id":"ms_053","category":"musculoskeletal","question":"반달(반월판) 연골 손상은 어떻게 치료하나요?","answer":"외상성 파열은 수술(부분 절제 또는 봉합), 퇴행성 파열은 재활 운동·체중 감량·물리치료 등 보존적 치료가 우선됩니다. 관절경으로 진단과 치료를 동시에 할 수 있습니다."},
  {"id":"ms_054","category":"musculoskeletal","question":"손 관절이 붓고 아픈 류마티스 관절염 치료는?","answer":"DMARDs(메토트렉세이트 등)로 질환 진행을 억제하는 것이 핵심입니다. 생물학적 제제(TNF-α 억제제, IL-6 억제제)도 사용됩니다. NSAIDs와 스테로이드는 급성기 증상 완화에 사용합니다."},
  {"id":"ms_055","category":"musculoskeletal","question":"연골이 닳으면 다시 자라나나요?","answer":"성인의 관절 연골은 혈관·신경이 없어 자연 재생이 매우 어렵습니다. 미세천공술, 자가 연골 이식, 줄기세포 치료 등으로 일부 재생을 유도할 수 있지만, 완전한 정상 연골 복원은 아직 한계가 있습니다."},
  {"id":"ms_056","category":"musculoskeletal","question":"노인에서 고관절 골절이 위험한 이유는?","answer":"고관절(엉덩이) 골절은 노인에서 1년 내 사망률이 20~30%에 달합니다. 수술 후 조기 거동이 폐렴·혈전·욕창을 예방합니다. 골다공증 예방과 낙상 방지가 고관절 골절 예방의 핵심입니다."},
  {"id":"ms_057","category":"musculoskeletal","question":"체외충격파 치료란 무엇인가요?","answer":"고에너지 음파를 통증 부위에 집중해 건증(건병증), 석회화 건염, 족저근막염의 치료에 사용합니다. 콜라겐 생성 자극, 신경 무감각화, 혈관 신생 촉진이 기전입니다. 비수술적 치료로 많이 활용됩니다."},
  {"id":"ms_058","category":"musculoskeletal","question":"운동선수에서 흔한 ACL(전방십자인대) 손상이란?","answer":"전방십자인대는 무릎 안정화의 핵심입니다. 방향 전환, 점프 착지, 충돌로 발생합니다. '뚝' 소리 후 빠른 부종이 특징입니다. 수술(관절경 재건) 후 9~12개월 재활이 필요하며 재발 위험을 낮춥니다."},
  {"id":"ms_059","category":"musculoskeletal","question":"정형외과에서 주사 치료에는 어떤 종류가 있나요?","answer":"코르티코스테로이드 주사(항염증), 히알루론산 주사(관절 윤활·쿠션), PRP 혈소판 풍부 혈장(조직 재생), 프롤로테라피(증식 치료), 신경 차단 주사 등이 근골격계 통증 치료에 활용됩니다."},
  {"id":"ms_060","category":"musculoskeletal","question":"골절 예방을 위해 낙상을 줄이는 방법은?","answer":"집 안 미끄럼 방지 매트 설치, 조명 밝게, 욕실 손잡이, 신발 뒷굽 적절, 시력 교정, 다약제 검토(어지럼증 유발 약물), 균형 감각 운동(타이치), 골다공증 치료가 낙상·골절 예방에 효과적입니다."},
  {"id":"ms_061","category":"musculoskeletal","question":"목 디스크(경추 추간판 탈출증)의 증상은?","answer":"목과 어깨 통증, 팔 저림·감각 저하, 팔 힘 약화가 주요 증상입니다. 심한 경우 척수 압박으로 하지 마비·보행 장애가 생깁니다. MRI로 확진하며 대부분 보존적 치료로 호전됩니다."},
  {"id":"ms_062","category":"musculoskeletal","question":"발목 외과 돌출(복사뼈) 아래 통증의 원인은?","answer":"복사뼈 아래 통증은 발목 인대 손상, 건초염(비골 건초염), 발 외측 인대 손상이 흔한 원인입니다. 발에 맞는 신발, 발목 안정화 운동, 족부 전문의 진료가 필요합니다."},
  {"id":"ms_063","category":"musculoskeletal","question":"좌골 신경통이란 무엇인가요?","answer":"좌골 신경(요추 4~5번, 천추 1~3번 신경근)이 압박되어 엉덩이·허벅지·종아리·발까지 뻗치는 방사통입니다. 허리 디스크, 이상근 증후군이 주요 원인이며, 물리치료·약물·신경 차단술로 치료합니다."},
  {"id":"ms_064","category":"musculoskeletal","question":"RICE 처치란 무엇인가요?","answer":"급성 근골격계 손상 초기 처치법입니다. R-안정(Rest), I-냉찜질(Ice, 48시간 이내), C-압박(Compression), E-거상(Elevation)입니다. 최근에는 POLICE(Protection·Optimal Loading·Ice·Compression·Elevation)로 확장되었습니다."},
  {"id":"ms_065","category":"musculoskeletal","question":"비타민 D가 근골격계 건강에 중요한 이유는?","answer":"비타민 D는 칼슘 흡수를 촉진해 뼈 건강에 필수입니다. 근육 기능에도 중요해 결핍 시 근력 저하와 낙상 위험이 높아집니다. 정상 혈중 비타민 D 수준(30ng/mL 이상) 유지가 권장됩니다."},
  {"id":"ms_066","category":"musculoskeletal","question":"무릎 인공관절 수술 후 재활 시작은 언제?","answer":"대부분 수술 당일 또는 다음날부터 보행 훈련을 시작합니다. 조기 거동이 혈전·폐렴·근위축을 예방합니다. 물리치료사 지도 하에 6~12주간 집중 재활로 90% 이상의 기능 회복이 가능합니다."},
  {"id":"ms_067","category":"musculoskeletal","question":"테니스·골프 엘보는 왜 생기나요?","answer":"반복적인 손목·전완부 사용으로 팔꿈치 외측(테니스엘보) 또는 내측(골프엘보) 힘줄에 과부하가 쌓여 미세 손상이 발생합니다. 컴퓨터 사용자에서도 흔합니다."},
  {"id":"ms_068","category":"musculoskeletal","question":"자세 교정을 위한 효과적인 운동은?","answer":"흉추 신전(폼롤러 흉추 이완), 어깨 후인(shoulder retraction), 고관절 굴곡근 스트레칭, 코어 안정화 운동(플랭크), 턱 당기기(목 자세 교정)가 전반적인 자세 개선에 효과적입니다."},
  {"id":"ms_069","category":"musculoskeletal","question":"뼈 건강을 위한 최적의 칼슘 섭취 방법은?","answer":"하루 1,000~1,200mg의 칼슘을 식이로 섭취하는 것이 이상적입니다. 500mg 이상은 한 번에 흡수가 어려우므로 나눠 섭취합니다. 우유·치즈 등 유제품, 두부, 멸치, 브로콜리가 좋은 칼슘 공급원입니다."},
  {"id":"ms_070","category":"musculoskeletal","question":"척추 협착증 보존적 치료는?","answer":"물리치료(신전 피하고 굴곡 자세 유지), 코어 강화 운동, 자전거 타기(굴곡 자세), NSAIDs, 경막외 스테로이드 주사가 효과적입니다. 통증 지속·보행 한계가 심하면 수술(감압술)을 고려합니다."},
  {"id":"ms_071","category":"musculoskeletal","question":"어깨 탈구 후 관리 방법은?","answer":"즉시 정복(관절 제자리) 후 3~4주 보조기 고정, 이후 점진적 재활 운동으로 근력과 안정성을 회복합니다. 반복 탈구가 있으면 관절경 봉합 수술을 고려합니다. 조기 재활 시작이 기능 회복을 빠르게 합니다."},
  {"id":"ms_072","category":"musculoskeletal","question":"등 통증 중 즉시 병원을 가야 할 경우는?","answer":"발열 동반 등 통증, 배변·배뇨 장애, 하지 마비·감각 소실, 배(복부) 쪽으로 퍼지는 통증, 외상 후 통증, 암 치료 중 새로 생긴 통증 시 즉시 응급 평가가 필요합니다."},
  {"id":"ms_073","category":"musculoskeletal","question":"소아에서 자주 나타나는 성장판 손상이란?","answer":"성장기 어린이의 성장판(골단판)은 성인 뼈보다 약해 비틀림이나 충격에 손상됩니다. 손상 후 성장 장애가 생길 수 있어 조기 정형외과 치료가 중요합니다. 무릎 주변 부상이 특히 주의가 필요합니다."},
  {"id":"ms_074","category":"musculoskeletal","question":"무릎 통증에 O다리와 X다리가 영향을 주나요?","answer":"O다리(내반슬)는 내측 무릎에, X다리(외반슬)는 외측 무릎에 과부하를 주어 편심 연골 마모를 일으킵니다. 맞춤 깔창, 하지 근력 강화, 체중 감량으로 부담을 줄이고 심한 경우 절골술(각도 교정)을 고려합니다."},
  {"id":"ms_075","category":"musculoskeletal","question":"만성 요통 환자에게 권장하는 운동 종류는?","answer":"걷기, 수영, 수중 에어로빅, 자전거 타기(낮은 강도), 요가·필라테스(코어 강화), 맥킨지 신전 운동이 만성 요통에 효과적입니다. 급성기에는 침대 안정보다 가벼운 활동 유지가 회복에 더 좋습니다."},
  {"id":"ms_076","category":"musculoskeletal","question":"건강한 척추를 위한 수면 자세는?","answer":"옆으로 잘 때 양쪽 무릎 사이에 베개를 끼워 골반 정렬을 유지합니다. 등을 대고 잘 때는 무릎 아래에 베개를 둡니다. 엎드려 자는 자세는 목과 허리에 과도한 회전 부하를 주어 피하는 것이 좋습니다."},
  {"id":"ms_077","category":"musculoskeletal","question":"골관절염 진단 후 수술을 피하는 방법은?","answer":"체중 감량(무릎 1kg 감량=4kg 부담 감소), 근력 강화(특히 대퇴사두근), 저충격 유산소 운동, 보조기 착용, 관절 내 히알루론산 주사, 적절한 진통 치료로 수술을 최대한 늦출 수 있습니다."},
  {"id":"ms_078","category":"musculoskeletal","question":"손발이 저리면 무슨 질환을 의심해야 하나요?","answer":"손발 저림의 원인은 척추 디스크·협착증(신경 압박), 당뇨병성 신경병증, 손목터널증후군, 레이노 현상, 비타민 B12 결핍, 갑상선 저하증 등이 있습니다. 2주 이상 지속 시 신경과·정형외과 진료가 필요합니다."},
  {"id":"ms_079","category":"musculoskeletal","question":"MRI와 X선 중 관절 검사에 어떤 것을 써야 하나요?","answer":"X선은 뼈 구조, 골절, 관절 간격 평가에 적합합니다. MRI는 연골, 인대, 힘줄, 연부 조직 손상을 평가하는 데 우수합니다. 초음파는 힘줄 병변을 실시간으로 확인하는 데 유용합니다."},
  {"id":"ms_080","category":"musculoskeletal","question":"엉덩이 통증의 주요 원인은?","answer":"고관절 관절염, 이상근 증후군(좌골 신경통), 고관절 충돌 증후군(FAI), 점액낭염(trochanteric bursitis), 스트레스 골절, 라브럼 손상이 흔한 원인입니다. 통증 부위와 특성으로 감별합니다."},
  {"id":"ms_081","category":"musculoskeletal","question":"노인의 근골격계 건강을 위한 운동 계획은?","answer":"근력 운동(주 2~3회): 스쿼트·레그프레스 등 하지 강화, 균형 운동(매일): 한발 서기·타이치, 유연성(매일): 스트레칭, 유산소(주 5회): 걷기·수영이 노인 근골격계 건강을 위한 균형 잡힌 운동 계획입니다."},
  {"id":"ms_082","category":"musculoskeletal","question":"과운동성 관절 증후군이란?","answer":"과도한 관절 이완성으로 관절이 정상 범위 이상으로 구부러지는 상태입니다. 에를러-단로스 증후군에서 심하게 나타납니다. 관절 불안정으로 잦은 탈구와 통증을 일으키며 근육 강화 운동이 핵심 치료입니다."},
  {"id":"ms_083","category":"musculoskeletal","question":"비타민 K2가 뼈 건강에 도움이 되나요?","answer":"비타민 K2는 뼈에 칼슘이 침착하도록 돕는 단백질(오스테오칼신)을 활성화합니다. 혈관 내 칼슘 침착을 줄이는 효과도 있습니다. 청국장, 낫토, 발효 치즈에 풍부하며 골다공증 치료 보조제로 연구 중입니다."},
  {"id":"ms_084","category":"musculoskeletal","question":"IT밴드 증후군이란?","answer":"대퇴 외측 장경인대(IT밴드)와 대퇴골 외측과 마찰로 생기는 달리기 손상입니다. 무릎 외측의 타는 통증이 특징입니다. 스트레칭, 폼롤러 마사지, 주행 거리 감소, 엉덩이 근력 강화가 치료에 효과적입니다."},
  {"id":"ms_085","category":"musculoskeletal","question":"드케르벵 건초염이란?","answer":"엄지 손목 부위의 장무지외전근과 단무지신전건 건초에 염증이 생기는 상태입니다. 엄지를 구부려 주먹 쥐고 손목을 새끼손가락 방향으로 구부리면(Finkelstein 테스트) 통증이 악화됩니다. 신생아 엄마에서 특히 흔합니다."},
  {"id":"ms_086","category":"musculoskeletal","question":"관절 소리가 나면 나쁜 건가요?","answer":"대부분의 관절 소리(크래킹)는 관절 내 가스 기포, 힘줄·인대 이동으로 생기며 무해합니다. 통증이 동반되거나 잠김 증상이 있으면 연골·인대 손상을 의심해 진료가 필요합니다."},
  {"id":"ms_087","category":"musculoskeletal","question":"발 뒤꿈치 통증(아킬레스건 통증)은 어떻게 치료하나요?","answer":"아킬레스건 병증은 편심성 종아리 운동(heel drop)이 가장 효과적입니다. 뒤꿈치 패드, 적합한 운동화, 체외충격파도 도움됩니다. 완전 파열은 수술적 봉합이 필요합니다."},
  {"id":"ms_088","category":"musculoskeletal","question":"뼈 건강과 장 건강의 관계는?","answer":"장은 칼슘과 비타민 D 흡수의 주요 경로입니다. 소장 질환(셀리악병, 크론병) 시 칼슘 흡수가 저해되어 골다공증 위험이 높아집니다. 장내 미생물도 뼈 대사에 영향을 준다는 연구가 있습니다."},
  {"id":"ms_089","category":"musculoskeletal","question":"근골격계 질환에서 도수 치료란?","answer":"물리치료사가 손으로 직접 시행하는 관절 가동화, 근육 이완, 척추 교정 등의 치료입니다. 목·허리 통증, 관절 구축(굳음), 근육 긴장 완화에 효과가 있습니다. 올바른 전문가에게 받는 것이 중요합니다."},
  {"id":"ms_090","category":"musculoskeletal","question":"근골격계 건강 유지의 핵심 요약은?","answer":"규칙적인 근력·유연성·균형 운동, 칼슘·비타민 D 충분 섭취, 표준 체중 유지, 올바른 자세, 금연, 낙상 예방, 조기 통증 치료, 정기 골밀도 검진이 평생 근골격계 건강을 지키는 핵심 원칙입니다."},
  {"id":"ms_091","category":"musculoskeletal","question":"운동 전후 스트레칭 차이는?","answer":"운동 전: 동적 스트레칭(다리 들어올리기, 팔 돌리기 등)으로 혈류 증가·근육 활성화. 운동 후: 정적 스트레칭(자세 유지 20~30초)으로 근육 회복 및 유연성 향상을 도모합니다. 정적 스트레칭을 운동 전에 하면 근력이 저하될 수 있습니다."},
  {"id":"ms_092","category":"musculoskeletal","question":"오랜 컴퓨터 작업으로 인한 목·어깨 통증 관리는?","answer":"1시간마다 5분 휴식, 모니터 눈 높이 맞추기, 어깨 으쓱 운동·목 스트레칭, 견갑골 사이 근육(능형근) 강화 운동, 인체공학적 의자·키보드 사용이 사무직 근골격계 통증 예방에 효과적입니다."},
  {"id":"ms_093","category":"musculoskeletal","question":"심한 무릎 통증에 스테로이드 주사가 효과적인가요?","answer":"코르티코스테로이드 관절 내 주사는 급성 염증 완화에 빠른 효과가 있습니다. 통상 2~3개월 효과가 지속됩니다. 반복 주사는 연골 손상·인대 약화를 유발할 수 있어 연간 3~4회 이내로 제한합니다."},
  {"id":"ms_094","category":"musculoskeletal","question":"어린이 평발은 치료해야 하나요?","answer":"7세 미만 어린이의 평발은 대부분 생리적으로 성장하면서 자연 교정됩니다. 통증이 있거나 7~8세 이후에도 교정되지 않으면 맞춤 깔창과 발 근육 강화 운동이 권장됩니다. 대부분 수술은 필요하지 않습니다."},
  {"id":"ms_095","category":"musculoskeletal","question":"발목 보조기(앵클 브레이스)를 착용해야 하는 경우는?","answer":"급성 발목 염좌(2~3도), 반복적 발목 불안정, 스포츠 복귀 초기, 고관절·무릎 수술 후 보상적 발목 불안정 시 착용합니다. 장기간 착용은 발목 주변 근육 약화를 유발할 수 있어 적정 기간 후 운동으로 대체합니다."},
  {"id":"ms_096","category":"musculoskeletal","question":"콜라겐 보충제가 관절 건강에 도움이 되나요?","answer":"일부 연구에서 가수분해 콜라겐 보충이 관절 통증과 기능 개선에 도움될 수 있음을 보고합니다. 그러나 효과 크기는 제한적이며 대규모 연구가 더 필요합니다. 비타민 C와 함께 복용 시 흡수에 도움됩니다."},
  {"id":"ms_097","category":"musculoskeletal","question":"십이지장 수술 후 골다공증이 생기는 이유는?","answer":"십이지장은 칼슘과 비타민 D의 주요 흡수 부위입니다. 위우회술이나 십이지장을 우회하는 수술 후에는 칼슘·비타민 D 흡수가 줄어 골다공증 위험이 높아집니다. 수술 후 적극적인 보충이 필요합니다."},
  {"id":"ms_098","category":"musculoskeletal","question":"허리 통증에 온찜질이 좋은가요, 냉찜질이 좋은가요?","answer":"급성 허리 통증(48시간 이내)에는 냉찜질이 부종 억제에 효과적입니다. 만성 허리 통증이나 근육 긴장에는 온찜질이 혈류를 높여 근육 이완과 통증 완화에 더 좋습니다. 15~20분씩 하루 3~4회 적용합니다."},
  {"id":"ms_099","category":"musculoskeletal","question":"운동 중 관절 통증이 있을 때 계속해야 하나요?","answer":"일반적인 근육 피로감은 계속 운동할 수 있습니다. 그러나 관절 통증(특히 날카롭거나 지속적인)은 멈춰야 한다는 신호입니다. 운동 후 48시간 이상 통증이 지속되면 의료진과 상담이 필요합니다."},
  {"id":"ms_100","category":"musculoskeletal","question":"근골격계 통증의 심리적 요인이 중요한가요?","answer":"네, 통증 파국화, 우울·불안, 낮은 자기효능감은 만성 통증 경험을 악화시킵니다. 인지행동치료(CBT), 수용전념치료(ACT)가 만성 근골격계 통증에 신체 치료와 병행할 때 효과적입니다."}
]

